  LESSON_QUESTIONS['Real Estate']['1031 Exchange'] = [
    { type: 'multiple_choice', prompt: 'What is a 1031 exchange?', options: ['A tax-deferred swap of one investment property for another', 'Trading stocks for real estate', 'Exchanging currency at a bank', 'A type of mortgage refinance'], correctAnswer: 'A tax-deferred swap of one investment property for another', difficulty: 'easy', explanation: 'A 1031 exchange (named after IRS Code Section 1031) lets you sell an investment property and reinvest the proceeds into a "like-kind" property while deferring capital gains taxes.' },
    { type: 'multiple_choice', prompt: 'How many days do you have to identify replacement properties in a 1031 exchange?', options: ['30 days', '45 days', '90 days', '180 days'], correctAnswer: '45 days', difficulty: 'medium', explanation: 'You must identify potential replacement properties within 45 days of selling your original property. The actual purchase must close within 180 days.' },
    { type: 'true_false', prompt: 'You can use a 1031 exchange for your primary residence.', options: ['True', 'False'], correctAnswer: 'False', difficulty: 'easy', explanation: '1031 exchanges only apply to investment or business properties. Personal residences and vacation homes (used primarily for personal purposes) do not qualify.' },
    { type: 'multiple_choice', prompt: 'What does "like-kind" mean in a 1031 exchange?', options: ['Any type of real estate for any other type of real estate', 'The exact same type of property', 'Properties of equal value only', 'Properties in the same state'], correctAnswer: 'Any type of real estate for any other type of real estate', difficulty: 'medium', explanation: 'Like-kind is broadly defined for real estate. You can exchange an apartment for a commercial building, vacant land, or any other investment real estate.' },
    { type: 'true_false', prompt: 'In a 1031 exchange, you must use a qualified intermediary to hold the funds.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'medium', explanation: 'You cannot touch the sale proceeds yourself. A qualified intermediary (QI) must hold the funds between the sale and purchase to maintain tax-deferred status.' },
    { type: 'multiple_choice', prompt: 'What is "boot" in a 1031 exchange?', options: ['Cash or non-like-kind property received that is taxable', 'A type of footwear inspection', 'The down payment amount', 'A boot camp for investors'], correctAnswer: 'Cash or non-like-kind property received that is taxable', difficulty: 'hard', explanation: 'Boot is any cash or non-qualifying property you receive in the exchange. It\'s taxable, so you should reinvest all proceeds to fully defer taxes.' },
    { type: 'true_false', prompt: 'You can do multiple 1031 exchanges over your lifetime, potentially deferring taxes indefinitely.', options: ['True', 'False'], correctAnswer: 'True', difficulty: 'hard', explanation: 'There\'s no limit on 1031 exchanges. Investors can chain exchanges throughout their careers, and at death, heirs receive a stepped-up basis, potentially eliminating the tax.' },
    { type: 'fill_gap', prompt: 'In a 1031 exchange, you must close on the replacement property within ___ days of selling the original.', options: ['45', '90', '180', '365'], correctAnswer: '180', difficulty: 'medium', explanation: 'The 180-day deadline to close on the replacement property is strict. Missing it means the entire exchange fails and taxes become due.' },
  ];

